code = """import json, re, pandas as pd, pathlib
# load clinical BRCA female with histology
a = json.loads(pathlib.Path(var_call_vL8mhjoam1K7Sjxcwe9cKEcf).read_text())
clin = pd.DataFrame(a)
# extract barcode from patient_description
clin['participant_barcode'] = clin['participant_barcode'].str.extract(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})', expand=False)
clin = clin.dropna(subset=['participant_barcode','histological_type']).drop_duplicates('participant_barcode')
# load CDH1 mutated participants (PASS)
cdh1 = pd.DataFrame(json.loads(pathlib.Path(var_call_OdZYUDxvtvwydIUCVd5Y91ET).read_text()))
cdh1_set = set(cdh1['participant_barcode'].dropna().unique())
# only consider participants present in mutation table with PASS (reliable entries)
allpass = pd.DataFrame(json.loads(pathlib.Path(var_call_iDs8l5svOQckP7ca5YFdAvFj).read_text()))
allpass_set = set(allpass['participant_barcode'].dropna().unique())
clin = clin[clin['participant_barcode'].isin(allpass_set)].copy()
clin['cdh1_mut'] = clin['participant_barcode'].isin(cdh1_set)
# contingency
tab = pd.crosstab(clin['histological_type'], clin['cdh1_mut'])
# add missing columns False/True
tab = tab.reindex(columns=[False, True], fill_value=0)
# exclude categories with marginal totals <=10
row_tot = tab.sum(axis=1)
keep = row_tot[row_tot>10].index
tab_f = tab.loc[keep]
# recompute chi-square
obs = tab_f.values.astype(float)
row_sums = obs.sum(axis=1, keepdims=True)
col_sums = obs.sum(axis=0, keepdims=True)
grand = obs.sum()
exp = row_sums @ (col_sums / grand)
chi2 = float(((obs-exp)**2/exp).sum())
res = {
  'chi_square_statistic': chi2,
  'grand_total_n': int(grand),
  'included_histology_categories': int(len(tab_f)),
  'contingency_table': tab_f.reset_index().rename(columns={'histological_type':'histological_type', False:'CDH1_no_mut', True:'CDH1_mut'}).to_dict(orient='records')
}
print('__RESULT__:')
print(json.dumps(res))"""

